function parseMoney(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'number') return value;
  const cleaned = String(value).replace(/[$,]/g, '').trim();
  if (!cleaned) return null;
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
}

function normalize(value) {
  return String(value ?? '')
    .trim()
    .toLowerCase()
    .replace(/^[^:]+:/, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/s+/g, ' ')
    .trim();
}

function categoryPrefix(value) {
  const text = String(value ?? '').trim().toLowerCase();
  if (!text.includes(':')) return null;
  return text.split(':', 1)[0].trim();
}

const prefixToMacro = {
  accounting: 'bookkeeping',
  'tax work': 'tax',
  payroll: 'payroll',
  advisory: 'advisory',
};

const serviceRecognitionRules = {
  '1040 advanced': ['tax', true, 'service_recognition_rule'],
  '1040 essentials': ['tax', true, 'service_recognition_rule'],
  '1040 plus': ['tax', true, 'service_recognition_rule'],
  '1065 advanced': ['tax', true, 'service_recognition_rule'],
  '1065 essential': ['tax', true, 'service_recognition_rule'],
  '1065 plus': ['tax', true, 'service_recognition_rule'],
  '1099 preparation': ['tax', false, 'needs_classification'],
  '1120 advanced': ['tax', true, 'service_recognition_rule'],
  '1120 essential': ['tax', true, 'service_recognition_rule'],
  '1120 plus': ['tax', true, 'service_recognition_rule'],
  '990 ez short form': ['tax', true, 'service_recognition_rule'],
  '990 full return essential': ['tax', true, 'service_recognition_rule'],
  '990 full return plus': ['tax', true, 'service_recognition_rule'],
  '990 t unrelated business': ['tax', true, 'service_recognition_rule'],
  'accounting advanced': ['bookkeeping', true, 'service_recognition_rule'],
  'accounting essential': ['bookkeeping', true, 'service_recognition_rule'],
  'accounting plus': ['bookkeeping', true, 'service_recognition_rule'],
  'annual estimate tax review': ['tax', true, 'service_recognition_rule'],
  'audit protection business': ['other', false, 'needs_classification'],
  'audit protection individual': ['other', false, 'needs_classification'],
  'fractional cfo': ['advisory', true, 'service_recognition_rule'],
  'payroll service': ['payroll', true, 'service_recognition_rule'],
  'payroll tax compliance': ['payroll', true, 'service_recognition_rule'],
  'sales tax compliance': ['sales_tax', true, 'service_recognition_rule'],
  'Sales Tax Compliance': ['sales_tax', true, 'profit_service_recognition_rules'],
  'setup and onboarding': ['advisory', true, 'service_recognition_rule'],
  'tangible property tax': ['tax', false, 'needs_classification'],
  'tpp florida': ['tax', false, 'needs_classification'],
  'work comp tax': ['payroll', false, 'needs_classification'],
  'year end accounting close': ['bookkeeping', false, 'needs_classification'],
  'advisory': ['advisory', true, 'service_recognition_rule'],
  'audit support service': ['advisory', true, 'service_recognition_rule'],
  'specialized services': ['advisory', false, 'needs_classification'],
  'billable expenses': ['pass_through', false, 'service_recognition_rule_pass_through'],
  'other income': ['pass_through', false, 'service_recognition_rule_pass_through'],
  'remote desktop access': ['pass_through', false, 'service_recognition_rule_pass_through'],
  'remote qbd access': ['pass_through', false, 'service_recognition_rule_pass_through'],
  'services': ['pass_through', false, 'service_recognition_rule_pass_through'],
};

function classify(row, parentIdsWithChildren) {
  const lineItemId = row.anchor_line_item_id;
  const qboProductName = row.qbo_product_name ?? '';
  const sourceName = row.name ?? '';
  const serviceName = row.service_name ?? row.name ?? row.qbo_product_name ?? '';

  if (row.is_bundle_parent && parentIdsWithChildren.has(lineItemId)) {
    return ['bundle_parent', false, 'bundle_parent_has_children'];
  }

  const normalizedService = normalize(serviceName);
  const normalizedProduct = normalize(qboProductName);
  const normalizedSource = normalize(sourceName);

  const serviceRule = serviceRecognitionRules[normalizedService]
    ?? serviceRecognitionRules[normalizedSource]
    ?? serviceRecognitionRules[normalizedProduct];
  if (serviceRule) return serviceRule;

  const prefixMacro = prefixToMacro[categoryPrefix(qboProductName)];
  if (prefixMacro) return [prefixMacro, true, 'qbo_category_prefix'];

  return ['other', false, 'needs_classification'];
}

const sourceRows = $input.all().map((item) => item.json);
const parentIdsWithChildren = new Set(
  sourceRows
    .map((row) => row.parent_line_item_id)
    .filter((value) => value !== undefined && value !== null && value !== '')
);

const classifiedRows = sourceRows.map((row) => {
  const amount = parseMoney(row.amount);
  const serviceName = row.service_name ?? row.name ?? row.qbo_product_name ?? null;
  const [macroServiceType, includeInRevenueAllocation, classificationReason] = classify(row, parentIdsWithChildren);
  return {
    anchor_line_item_id: row.anchor_line_item_id,
    anchor_invoice_id: row.anchor_invoice_id,
    anchor_relationship_id: row.anchor_relationship_id ?? null,
    parent_line_item_id: row.parent_line_item_id ?? null,
    service_name: serviceName,
    qbo_product_name: row.qbo_product_name ?? null,
    source_name: row.name ?? null,
    amount,
    revenue_amount: includeInRevenueAllocation && amount !== null ? amount : 0,
    macro_service_type: macroServiceType,
    include_in_revenue_allocation: includeInRevenueAllocation,
    classification_reason: classificationReason,
    classified_at: new Date().toISOString(),
  };
});

const byMacro = classifiedRows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});
const unclassified = classifiedRows.filter((row) => row.classification_reason === 'needs_classification');
const includedRevenueAmount = classifiedRows.reduce((sum, row) => sum + Number(row.revenue_amount ?? 0), 0);

return [
  {
    json: {
      classifiedRows,
      summary: {
        classifiedLineItems: classifiedRows.length,
        unclassifiedLineItems: unclassified.length,
        includedRevenueAmount: Math.round(includedRevenueAmount * 100) / 100,
        byMacro,
        unclassifiedSample: unclassified.slice(0, 10),
      },
    },
  },
];

const rows = $input.all().map((item) => item.json);
const byMacro = rows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});
const unclassified = rows.filter((row) => row.classification_reason === 'unclassified_qbo_product');
const includedRevenueAmount = rows.reduce((sum, row) => sum + Number(row.revenue_amount ?? 0), 0);
return [
  {
    json: {
      status: 'ok',
      upsertedClassificationCount: rows.length,
      unclassifiedLineItems: unclassified.length,
      includedRevenueAmount: Math.round(includedRevenueAmount * 100) / 100,
      byMacro,
      sample: rows.slice(0, 10),
      unclassifiedSample: unclassified.slice(0, 10),
    },
  },
];
